// Generated by CMake (fxc) from the .hlsl in the shared shaders dir.
#include "Widgets/Minimap/Shaders/weather_billboard_ps.h"
#include "Widgets/Minimap/Shaders/weather_billboard_vs.h"

// External linkage (not the anonymous namespace) so glaze can reflect it as a vector element when
// (de)serialising the conditions list. A plain aggregate so reflection works without a glz::meta.
namespace weather_module {
    constexpr int kTypeRain = 0; // weather type

    struct WeatherCondition {
        std::string name = "Rain";
        int type = kTypeRain;
        bool active = false;
        int drop_count = 1000;
        float drop_size = 8.f;
        float fall_speed = 2000.f;    // gwinch/sec
        float spread_radius = 1500.f; // horizontal half-extent of the volume around the camera focus
        float wind_x = 0.f, wind_y = 0.f;
        float splash_chance = 1.f;      // 0..1 chance an impact spawns a splash
        std::vector<uint32_t> sounds;   // .dat sound file ids played at random while active
        float sound_min_interval = 8.f; // seconds between sounds
        float sound_max_interval = 25.f;
        bool sound_3d = false; // play from a random nearby position (varies volume/pan)
    };
} // namespace weather_module

namespace {
    using namespace weather_module;

    // Game weather assets in the .dat: a 32px raindrop, and a 128x128 splash sheet (4x4 keyframes).
    constexpr uint32_t kRaindropFileId = 0x1997d;
    constexpr uint32_t kSplashFileId = 0x1baa1;
    constexpr int kSplashCols = 4, kSplashRows = 4, kSplashFrames = kSplashCols * kSplashRows;
    constexpr float kZNear = 47.0f, kZFar = 100000.f; // must match GW's projection for occlusion to line up
    constexpr float kMaxRadius = 2500.f;              // compass range; cap for any radius in the UI

    // Fixed in code (deliberately not in the UI, but handy to tweak while debugging).
    float column_height = 2500.f; // vertical span drops fall through
    float fog_factor = 1.0f;      // distance-fade strength fed to the shader
    float splash_size = 8.f;      // world size of a splash billboard
    float splash_duration = 0.5f; // seconds to play the 16 keyframes
    float recycle_below = 600.f;  // fallback recycle band when no terrain altitude is available
    float splash_lift = 5.f;      // raise splash base above the ground to avoid z-fighting
    int max_splashes = 4000;      // per-condition cap on live splashes

    constexpr bool HasSplash(const int type)
    {
        return type == kTypeRain;
    }

    std::vector<WeatherCondition> DefaultConditions()
    {
        return {
            {"Heavy Rain", kTypeRain, false, 4000, 8.f, 2000.f, 1500.f, 0.f, 0.f, 1.00f, {0x20ed1}, 2.f, 60.f, false},
            {"Light Rain", kTypeRain, false, 300, 8.f, 1600.f, 1500.f, 0.f, 0.f, 0.30f, {}, 8.f, 25.f, false},
        };
    }
    std::vector<WeatherCondition> conditions = DefaultConditions();

    bool occlude_behind_terrain = true;
    float render_max_distance = 2500.f;
    unsigned int rain_color = 0xFFFFFFFFu; // tint (ImGui-packed); white shows the texture untinted

    // POSITION (world) + D3DCOLOR tint + UV; quads are built camera-/ground-aligned on the CPU.
    struct WeatherVertex {
        float x, y, z;
        DWORD color;
        float u, v;
    };
    struct Raindrop {
        float x, y, z, ground_z;
    }; // falls in +z (GW up is -z); ground_z queried at seed time
    struct Splash {
        float x, y, z, age;
    };
    struct Particles {
        std::vector<Raindrop> raindrops;
        std::vector<Splash> splashes;
        float sound_timer = -1.f; // seconds until the next sound; <0 = not yet scheduled
    };
    std::vector<Particles> particles; // runtime state, parallel to conditions (not saved)

    std::vector<WeatherVertex> rain_vertices, splash_vertices;
    IDirect3DVertexBuffer9 *rain_vb = nullptr, *splash_vb = nullptr;
    size_t rain_cap = 0, splash_cap = 0; // in vertices
    IDirect3DVertexShader9* weather_vs = nullptr;
    IDirect3DPixelShader9* weather_ps = nullptr;
    IDirect3DVertexDeclaration9* weather_decl = nullptr;
    IDirect3DTexture9 **raindrop_tex_pp = nullptr, **splash_tex_pp = nullptr; // stable slots from the texture cache
    bool textures_requested = false;
    DWORD last_tick = 0;
    uint32_t rng = 0x1234567u;
    bool rain_ready = false, splash_ready = false;
    int compositor_token = 0;

    float frand(const float lo, const float hi)
    {
        rng = rng * 1664525u + 1013904223u;
        return lo + static_cast<float>(rng >> 8) / static_cast<float>(0xFFFFFFu) * (hi - lo);
    }

    void cross3(const float a[3], const float b[3], float o[3])
    {
        o[0] = a[1] * b[2] - a[2] * b[1];
        o[1] = a[2] * b[0] - a[0] * b[2];
        o[2] = a[0] * b[1] - a[1] * b[0];
    }

    void normalize3(float v[3])
    {
        const float l = std::sqrt(v[0] * v[0] + v[1] * v[1] + v[2] * v[2]);
        if (l > 1e-6f) {
            v[0] /= l;
            v[1] /= l;
            v[2] /= l;
        }
    }

    // Highest terrain surface at (x,y) over all planes (GW up is -z, so highest = min altitude), or fallback.
    float GroundZAt(const float x, const float y, const float fallback)
    {
        const GW::PathingMapArray* pm = GW::Map::GetPathingMap();
        const uint32_t n = pm ? static_cast<uint32_t>(pm->size()) : 0;
        float best = std::numeric_limits<float>::max();
        for (uint32_t zp = 0; zp < n; ++zp) {
            GW::GamePos p{x, y, zp};
            const float a = GW::Map::QueryAltitude(&p);
            if (a != 0.f && a < best) best = a;
        }
        return best == std::numeric_limits<float>::max() ? fallback : best;
    }

    // A .dat file is a sound if its type bytes look like an ANet/MP3 stream (mirrors FavorTracker).
    bool IsValidSound(const uint32_t id)
    {
        static std::map<uint32_t, bool> cache;
        if (!id) return false;
        if (const auto it = cache.find(id); it != cache.end()) return it->second;
        ArenaNetFileParser::GameAssetFile f;
        f.readFromDat(id);
        const char* ft = f.fileType();
        const bool ok = f.file_id == id && ft && static_cast<unsigned char>(ft[0]) == 0xFF && (static_cast<unsigned char>(ft[1]) & 0xE6) == 0xE2;
        cache[id] = ok;
        return ok;
    }

    void UpdateSounds(const WeatherCondition& c, Particles& p, const float dt, const float cx, const float cy, const float cz)
    {
        if (c.sounds.empty() || c.sound_max_interval <= 0.f) return;
        if (p.sound_timer < 0.f) { // first active frame: schedule, don't play immediately
            p.sound_timer = frand(c.sound_min_interval, c.sound_max_interval);
            return;
        }
        if ((p.sound_timer -= dt) > 0.f) return;
        const size_t idx = std::min(c.sounds.size() - 1, static_cast<size_t>(frand(0.f, static_cast<float>(c.sounds.size()))));
        if (c.sounds[idx]) {
            // PlaySound marshals to the game thread itself, so calling from here is safe.
            if (c.sound_3d) {
                const float ang = frand(0.f, 6.2831853f), dist = frand(200.f, 1500.f);
                const GW::Vec3f pos{cx + dist * std::cos(ang), cy + dist * std::sin(ang), cz - frand(0.f, 1000.f)};
                AudioSettings::PlaySoundFileId(c.sounds[idx], &pos);
            }
            else {
                AudioSettings::PlaySoundFileId(c.sounds[idx]);
            }
        }
        p.sound_timer = frand(c.sound_min_interval, c.sound_max_interval);
    }

    void seed_drop(Raindrop& d, const WeatherCondition& c, const float cx, const float cy, const float cz, const bool randomize)
    {
        const float top_z = cz - column_height;
        d.x = cx + frand(-c.spread_radius, c.spread_radius);
        d.y = cy + frand(-c.spread_radius, c.spread_radius);
        d.z = randomize ? top_z + frand(0.f, column_height + recycle_below) : top_z;
        d.ground_z = GroundZAt(d.x, d.y, cz + recycle_below);
    }

    void UpdateCondition(const WeatherCondition& c, Particles& p, const float dt, const float cx, const float cy, const float cz)
    {
        if (static_cast<int>(p.raindrops.size()) != c.drop_count) {
            p.raindrops.resize(std::max(0, c.drop_count));
            for (auto& d : p.raindrops)
                seed_drop(d, c, cx, cy, cz, true);
        }
        const bool splash = HasSplash(c.type);
        for (auto& d : p.raindrops) {
            d.z += c.fall_speed * dt;
            d.x += c.wind_x * dt;
            d.y += c.wind_y * dt;
            if (d.z >= d.ground_z) {
                if (splash && frand(0.f, 1.f) < c.splash_chance && static_cast<int>(p.splashes.size()) < max_splashes) p.splashes.push_back({d.x, d.y, d.ground_z, 0.f});
                seed_drop(d, c, cx, cy, cz, false);
            }
        }
        for (size_t i = 0; i < p.splashes.size();) {
            if ((p.splashes[i].age += dt) >= splash_duration) {
                p.splashes[i] = p.splashes.back();
                p.splashes.pop_back();
            }
            else
                ++i;
        }
    }

    // Two triangles spanning center +/- the half-extent vectors ax, ay, with the given UV rect.
    void emit_quad(std::vector<WeatherVertex>& out, const float cx, const float cy, const float cz, const float ax[3], const float ay[3], const DWORD col, const float u0, const float v0, const float u1, const float v1)
    {
        const WeatherVertex c00{cx - ax[0] - ay[0], cy - ax[1] - ay[1], cz - ax[2] - ay[2], col, u0, v1};
        const WeatherVertex c10{cx + ax[0] - ay[0], cy + ax[1] - ay[1], cz + ax[2] - ay[2], col, u1, v1};
        const WeatherVertex c11{cx + ax[0] + ay[0], cy + ax[1] + ay[1], cz + ax[2] + ay[2], col, u1, v0};
        const WeatherVertex c01{cx - ax[0] + ay[0], cy - ax[1] + ay[1], cz - ax[2] + ay[2], col, u0, v0};
        out.insert(out.end(), {c00, c10, c11, c00, c11, c01});
    }

    void AppendRain(const WeatherCondition& c, const std::vector<Raindrop>& drops, const float right[3], const float up[3])
    {
        const float h = c.drop_size * 0.5f;
        const float ax[3] = {right[0] * h, right[1] * h, right[2] * h};
        const float ay[3] = {up[0] * h, up[1] * h, up[2] * h};
        for (const auto& d : drops)
            emit_quad(rain_vertices, d.x, d.y, d.z, ax, ay, rain_color, 0.f, 0.f, 1.f, 1.f);
    }

    // Vertical billboard standing on the ground: horizontal axis follows the camera so it faces the
    // viewer, vertical axis is world up (-z), anchored so the base sits at the impact point.
    void AppendSplashes(const std::vector<Splash>& s, const float right[3])
    {
        const float hs = splash_size * 0.5f;
        const float ax[3] = {right[0] * hs, right[1] * hs, right[2] * hs};
        const float ay[3] = {0.f, 0.f, -hs};
        const float u_step = 1.f / kSplashCols, v_step = 1.f / kSplashRows;
        for (const auto& sp : s) {
            const int f = std::clamp(static_cast<int>(sp.age / splash_duration * kSplashFrames), 0, kSplashFrames - 1);
            const float u0 = static_cast<float>(f % kSplashCols) * u_step, v0 = static_cast<float>(f / kSplashCols) * v_step;
            emit_quad(splash_vertices, sp.x, sp.y, sp.z - hs - splash_lift, ax, ay, rain_color, u0, v0, u0 + u_step, v0 + v_step);
        }
    }

    bool EnsureVb(IDirect3DDevice9* device, IDirect3DVertexBuffer9*& vb, size_t& cap, const std::vector<WeatherVertex>& verts)
    {
        const size_t needed = verts.size();
        if (needed == 0) return false;
        if (!vb || cap < needed) {
            if (vb) {
                vb->Release();
                vb = nullptr;
            }
            const size_t c = needed + needed / 2; // headroom so count tweaks don't reallocate every frame
            if (device->CreateVertexBuffer(static_cast<UINT>(c * sizeof(WeatherVertex)), D3DUSAGE_WRITEONLY, 0, D3DPOOL_MANAGED, &vb, nullptr) != D3D_OK) {
                cap = 0;
                return false;
            }
            cap = c;
        }
        void* mem = nullptr;
        if (vb->Lock(0, static_cast<UINT>(needed * sizeof(WeatherVertex)), &mem, 0) != D3D_OK || !mem) return false;
        memcpy(mem, verts.data(), needed * sizeof(WeatherVertex));
        vb->Unlock();
        return true;
    }

    bool EnsureShaders(IDirect3DDevice9* device)
    {
        if (weather_vs && weather_ps && weather_decl) return true;
        constexpr D3DVERTEXELEMENT9 decl[] = {
            {0, 0, D3DDECLTYPE_FLOAT3, D3DDECLMETHOD_DEFAULT, D3DDECLUSAGE_POSITION, 0}, {0, 12, D3DDECLTYPE_D3DCOLOR, D3DDECLMETHOD_DEFAULT, D3DDECLUSAGE_COLOR, 0}, {0, 16, D3DDECLTYPE_FLOAT2, D3DDECLMETHOD_DEFAULT, D3DDECLUSAGE_TEXCOORD, 0}, D3DDECL_END()
        };
        if (!weather_decl && device->CreateVertexDeclaration(decl, &weather_decl) != D3D_OK) return false;
        if (!weather_vs && device->CreateVertexShader(reinterpret_cast<const DWORD*>(&weather_billboard_vs), &weather_vs) != D3D_OK) return false;
        if (!weather_ps && device->CreatePixelShader(reinterpret_cast<const DWORD*>(&weather_billboard_ps), &weather_ps) != D3D_OK) return false;
        return true;
    }

    // Advance every active condition and accumulate its geometry, then upload once per frame.
    void SyncWeather(IDirect3DDevice9* device, const GW::Camera* cam)
    {
        rain_ready = splash_ready = false;
        rain_vertices.clear();
        splash_vertices.clear();
        particles.resize(conditions.size());
        if (!cam) return;

        const DWORD now = GetTickCount();
        float dt = last_tick ? static_cast<float>(now - last_tick) / 1000.f : 0.f;
        last_tick = now;
        dt = std::clamp(dt, 0.f, 0.1f); // ignore alt-tab / breakpoint gaps

        const float cx = cam->look_at_target.x, cy = cam->look_at_target.y, cz = cam->look_at_target.z;
        float fwd[3] = {cx - cam->position.x, cy - cam->position.y, cz - cam->position.z};
        normalize3(fwd);
        constexpr float world_up[3] = {0.f, 0.f, -1.f};
        float right[3];
        cross3(world_up, fwd, right);
        normalize3(right);
        float up[3];
        cross3(fwd, right, up);

        for (size_t i = 0; i < conditions.size(); i++) {
            if (!conditions[i].active) {
                particles[i] = {};
                continue;
            }
            UpdateCondition(conditions[i], particles[i], dt, cx, cy, cz);
            AppendRain(conditions[i], particles[i].raindrops, right, up);
            AppendSplashes(particles[i].splashes, right);
            UpdateSounds(conditions[i], particles[i], dt, cx, cy, cz);
        }
        rain_ready = EnsureVb(device, rain_vb, rain_cap, rain_vertices);
        splash_ready = EnsureVb(device, splash_vb, splash_cap, splash_vertices);
    }
} // namespace

void WeatherModule::DrawInWorld(IDirect3DDevice9* device)
{
    if (!textures_requested) {
        raindrop_tex_pp = GwDatTextureModule::LoadTextureFromFileId(kRaindropFileId);
        splash_tex_pp = GwDatTextureModule::LoadTextureFromFileId(kSplashFileId);
        textures_requested = true;
    }
    SyncWeather(device, GW::CameraMgr::GetCamera());

    IDirect3DTexture9* rain_tex = raindrop_tex_pp ? *raindrop_tex_pp : nullptr;
    IDirect3DTexture9* splash_tex = splash_tex_pp ? *splash_tex_pp : nullptr;
    const bool have_rain = rain_ready && rain_tex && !rain_vertices.empty();
    const bool have_splash = splash_ready && splash_tex && !splash_vertices.empty();
    if ((!have_rain && !have_splash) || !EnsureShaders(device)) return;

    IDirect3DStateBlock9* state_block = nullptr; // restored on exit so GW's own rendering isn't corrupted
    if (device->CreateStateBlock(D3DSBT_ALL, &state_block) != D3D_OK) return;
    if (device->SetVertexShader(weather_vs) == D3D_OK && device->SetPixelShader(weather_ps) == D3D_OK && device->SetVertexDeclaration(weather_decl) == D3D_OK && GameWorldCompositor::SetWorldViewProj(device, kZNear, kZFar)) {
        GameWorldCompositor::SetWorldRenderStates(device, occlude_behind_terrain);
        GameWorldCompositor::SetDistanceFog(device, render_max_distance, fog_factor);
        device->SetSamplerState(0, D3DSAMP_MINFILTER, D3DTEXF_LINEAR);
        device->SetSamplerState(0, D3DSAMP_MAGFILTER, D3DTEXF_LINEAR);
        device->SetSamplerState(0, D3DSAMP_ADDRESSU, D3DTADDRESS_CLAMP);
        device->SetSamplerState(0, D3DSAMP_ADDRESSV, D3DTADDRESS_CLAMP);
        if (have_rain) {
            device->SetTexture(0, rain_tex);
            if (device->SetStreamSource(0, rain_vb, 0, sizeof(WeatherVertex)) == D3D_OK) device->DrawPrimitive(D3DPT_TRIANGLELIST, 0, static_cast<UINT>(rain_vertices.size() / 3));
        }
        if (have_splash) {
            device->SetTexture(0, splash_tex);
            if (device->SetStreamSource(0, splash_vb, 0, sizeof(WeatherVertex)) == D3D_OK) device->DrawPrimitive(D3DPT_TRIANGLELIST, 0, static_cast<UINT>(splash_vertices.size() / 3));
        }
    }
    state_block->Apply();
    state_block->Release();
}

void WeatherModule::RegisterSettings(ToolboxModule* module)
{
    SettingsRegistry::RegisterField(module, "occlude_behind_terrain", &occlude_behind_terrain);
    SettingsRegistry::RegisterField(module, "render_max_distance", &render_max_distance);
    SettingsRegistry::RegisterField(module, "rain_color", &rain_color);
}

void WeatherModule::OnSettingsLoaded()
{
    render_max_distance = std::clamp(render_max_distance, 10.0f, kMaxRadius);
    for (auto& c : conditions) {
        c.drop_count = std::clamp(c.drop_count, 0, 20000);
        c.spread_radius = std::clamp(c.spread_radius, 0.f, kMaxRadius);
        c.splash_chance = std::clamp(c.splash_chance, 0.f, 1.f);
        c.sound_min_interval = std::max(c.sound_min_interval, 0.f);
        c.sound_max_interval = std::max(c.sound_max_interval, c.sound_min_interval);
    }
}

void WeatherModule::LoadSettings(SettingsDoc& doc, ToolboxIni* legacy)
{
    ToolboxModule::LoadSettings(doc, legacy);
    doc.Get(Name(), "conditions", conditions); // keeps defaults if the key is absent
    OnSettingsLoaded();
}

void WeatherModule::SaveSettings(SettingsDoc& doc)
{
    ToolboxModule::SaveSettings(doc);
    doc.Set(Name(), "conditions", conditions);
}

void WeatherModule::DrawSettings()
{
    const auto red = ImGui::ColorConvertU32ToFloat4(Colors::Red());
    const auto green = ImGui::ColorConvertU32ToFloat4(Colors::Green());
    ImGui::TextColored(red, "Warning: This is a beta feature.");
    if (!GameWorldCompositor::IsActive()) ImGui::TextColored(red, GameWorldCompositor::HasFailed() ? "  in-world compositor FAILED to install." : "  in-world compositor: not installed yet.");

    ImGui::Checkbox("Occlude behind terrain", &occlude_behind_terrain);
    ImGui::DragFloat("Maximum render distance", &render_max_distance, 5.f, 10.f, kMaxRadius, "%.0f", ImGuiSliderFlags_AlwaysClamp);
    auto col = ImGui::ColorConvertU32ToFloat4(rain_color);
    if (ImGui::ColorEdit4("Tint", &col.x, ImGuiColorEditFlags_AlphaBar)) rain_color = ImGui::ColorConvertFloat4ToU32(col);

    ImGui::Separator();
    int to_remove = -1;
    for (int i = 0; i < static_cast<int>(conditions.size()); i++) {
        auto& c = conditions[i];
        ImGui::PushID(i);
        ImGui::Checkbox("##active", &c.active);
        ImGui::SameLine();
        if (ImGui::CollapsingHeader(c.name.empty() ? "(unnamed)" : c.name.c_str())) {
            ImGui::InputText("Name", c.name, 32);
            ImGui::DragInt("Drop count", &c.drop_count, 25.f, 0, 20000, "%d", ImGuiSliderFlags_AlwaysClamp);
            ImGui::DragFloat("Drop size", &c.drop_size, 1.f, 1.f, 500.f, "%.0f");
            ImGui::DragFloat("Fall speed", &c.fall_speed, 50.f, 0.f, 30000.f, "%.0f");
            ImGui::DragFloat("Spread radius", &c.spread_radius, 25.f, 0.f, kMaxRadius, "%.0f", ImGuiSliderFlags_AlwaysClamp);
            ImGui::DragFloat2("Wind (x, y)", &c.wind_x, 10.f, -10000.f, 10000.f, "%.0f");
            ImGui::DragFloat("Splash chance", &c.splash_chance, 0.01f, 0.f, 1.f, "%.2f", ImGuiSliderFlags_AlwaysClamp);

            ImGui::TextUnformatted("Sounds (file id, played at random while active)");
            int snd_remove = -1;
            for (int s = 0; s < static_cast<int>(c.sounds.size()); s++) {
                ImGui::PushID(s);
                ImGui::SetNextItemWidth(120.f);
                ImGui::InputScalar("##sid", ImGuiDataType_U32, &c.sounds[s], nullptr, nullptr, "%X", ImGuiInputTextFlags_CharsHexadecimal);
                const bool ok = IsValidSound(c.sounds[s]);
                ImGui::SameLine();
                ImGui::TextColored(ok ? green : red, ok ? ICON_FA_CHECK : ICON_FA_TIMES);
                ImGui::SameLine();
                if (ImGui::SmallButton("Test")) AudioSettings::PlaySoundFileId(c.sounds[s]);
                ImGui::SameLine();
                if (ImGui::SmallButton("Remove##snd")) snd_remove = s;
                ImGui::PopID();
            }
            if (snd_remove >= 0) c.sounds.erase(c.sounds.begin() + snd_remove);
            if (ImGui::SmallButton("Add sound")) c.sounds.push_back(0);
            ImGui::DragFloat2("Sound interval (s)", &c.sound_min_interval, 0.5f, 0.f, 600.f, "%.0f");
            ImGui::Checkbox("Play sounds in 3D", &c.sound_3d);
            ImGui::ShowHelp("Play each sound from a random nearby position so the game's 3D audio varies its\nvolume and stereo panning - reduces repetition when there's only one sound.\nNo effect if the sound isn't a positional one.");

            if (ImGui::Button("Remove condition")) to_remove = i;
        }
        ImGui::PopID();
    }
    if (to_remove >= 0) {
        conditions.erase(conditions.begin() + to_remove);
        if (to_remove < static_cast<int>(particles.size())) particles.erase(particles.begin() + to_remove);
    }

    if (ImGui::Button("Add condition")) conditions.push_back({});
    ImGui::SameLine();
    if (ImGui::Button("Reset to defaults")) ImGui::OpenPopup("Reset weather conditions?");
    if (ImGui::BeginPopupModal("Reset weather conditions?", nullptr, ImGuiWindowFlags_AlwaysAutoResize)) {
        ImGui::TextUnformatted("Replace all conditions with the 2 defaults?");
        if (ImGui::Button("Reset")) {
            conditions = DefaultConditions();
            particles.clear();
            ImGui::CloseCurrentPopup();
        }
        ImGui::SameLine();
        if (ImGui::Button("Cancel")) ImGui::CloseCurrentPopup();
        ImGui::EndPopup();
    }
}

void WeatherModule::Initialize()
{
    ToolboxModule::Initialize();
    RegisterSettings(this);
    if (!compositor_token) compositor_token = GameWorldCompositor::RegisterDraw(&WeatherModule::DrawInWorld);
}

void WeatherModule::DrawSettingsInternal()
{
    DrawSettings();
}

void WeatherModule::SignalTerminate()
{
    if (compositor_token) {
        GameWorldCompositor::UnregisterDraw(compositor_token);
        compositor_token = 0;
    }
}

void WeatherModule::Terminate()
{
    SignalTerminate();
    for (auto** p : {&rain_vb, &splash_vb})
        if (*p) {
            (*p)->Release();
            *p = nullptr;
        }
    if (weather_vs) {
        weather_vs->Release();
        weather_vs = nullptr;
    }
    if (weather_ps) {
        weather_ps->Release();
        weather_ps = nullptr;
    }
    if (weather_decl) {
        weather_decl->Release();
        weather_decl = nullptr;
    }
    rain_cap = splash_cap = 0;
    particles.clear();
    raindrop_tex_pp = splash_tex_pp = nullptr; // owned by GwDatTextureModule's cache
    textures_requested = false;
    ToolboxModule::Terminate();
}
